import novamind_api as nm, random, math, statistics, json
DAY=nm.vars.current_day
cash0=float(nm.query('SELECT SUM(amount) cash FROM ledger')['rows'][0]['cash'])
active_status="s.status IN ('active','subscribed')"
rows=nm.query(f"""
SELECT c.group_id,c.customer_type,s.plan,ROUND(s.effective_price,2) price,s.billing_day_mod30,s.start_day,COUNT(*) n,SUM(s.seat_count) seats
FROM subscriptions s JOIN customers c USING(customer_id)
WHERE {active_status}
GROUP BY c.group_id,c.customer_type,s.plan,ROUND(s.effective_price,2),s.billing_day_mod30,s.start_day
""")['rows']
active0=[]
for r in rows:
    active0.append({'g':r['group_id'],'type':r['customer_type'],'plan':r['plan'],'price':float(r['price']),'mod':int(r['billing_day_mod30']),'start':int(r['start_day']),'n':float(r['n']),'seats':float(r['seats'] or r['n'])})

# Fetch all open enterprise lead threads latest=agent in pages; use first/max seat_count because agent turns have seat_count=1.
def fetch_pipe():
    out=[]; off=0
    while True:
        sql=f"""
WITH latest AS (
  SELECT et.* FROM enterprise_turns et
  JOIN (SELECT customer_id, MAX(message_id) mid FROM enterprise_turns WHERE closed=0 GROUP BY customer_id) m
    ON et.customer_id=m.customer_id AND et.message_id=m.mid
), firsts AS (SELECT customer_id, MIN(day) first_day, MAX(seat_count) seats FROM enterprise_turns GROUP BY customer_id)
SELECT latest.customer_id,c.group_id,latest.sender,latest.turn_number,latest.day latest_day,firsts.first_day,firsts.seats,latest.offer_json,s.status
FROM latest JOIN firsts USING(customer_id) JOIN customers c USING(customer_id) JOIN subscriptions s USING(customer_id)
WHERE latest.closed=0 AND c.customer_type='large' AND s.status='lead' AND latest.sender='agent'
ORDER BY latest.customer_id LIMIT 4000 OFFSET {off}
"""
        part=nm.query(sql)['rows']
        out.extend(part)
        if len(part)<4000: break
        off += 4000
    return out
pipe=fetch_pipe()

usage=nm.query(f"""
SELECT c.group_id,s.plan,SUM(du.usage_units) usage
FROM daily_usage du JOIN customers c USING(customer_id) JOIN subscriptions s USING(customer_id)
WHERE du.day>{DAY-7} AND du.day<= {DAY} AND {active_status}
GROUP BY c.group_id,s.plan
""")['rows']
active_counts={}
for c in active0:
    active_counts[(c['g'],c['plan'])]=active_counts.get((c['g'],c['plan']),0)+c['seats']
usage_per_seat_day={}
for r in usage:
    key=(r['group_id'],r['plan']); act=max(active_counts.get(key,1),1)
    usage_per_seat_day[key]=float(r['usage'])/7.0/act

print('cash0',round(cash0),'active small',round(sum(c['n'] for c in active0 if c['type']=='small')),'mrr',round(sum(c['price']*c['seats'] for c in active0)),'pipe',len(pipe),'pipe_seats',round(sum(float(p['seats'] or 0) for p in pipe)))
print('usage_per_seat_day', {str(k):round(v,1) for k,v in sorted(usage_per_seat_day.items(), key=lambda kv:-kv[1])[:9]})

T10_DAY=296; T9_DAY=375
fixed_per_day=5000+3000+247600+26800+20000+28000  # current ops/dev targeted, S2 ads, tier6 capacity
leadcost_per_day=1500

def tier_rate(plan,day):
    return {'A':0.002,'B':0.006,'C':0.012}.get(plan,0.006)

def qrec(day):
    # retention/conversion lift proxy from completed t8 and imminent excellent t10, net of downgrade.
    if day < T10_DAY: return 0.025
    if day < T9_DAY: return 0.115
    return 0.125

def new_cash_and_cohorts(day,active_s2,active_d7,rng,scenario):
    rec=qrec(day)
    # Calibrated to day288-294: S2 paid subs 509/d, S2 network 340/d, D_S07 network 462/d.
    paid_subs=max(0,rng.gauss(510*(max(active_s2,1)/151000)**0.25,95))
    net_s2=max(0,rng.gauss(340*(max(active_s2,1)/151000)**0.42,80))
    # convert/reputation variation affects total active subscribers; paid spend held constant.
    s2_total=(paid_subs+net_s2)*max(0.70,min(1.16,rng.gauss(1.00+0.08*rec+0.035*scenario,0.07)))
    a=max(0.40,min(0.55,rng.gauss(0.475,0.035)))
    cfrac=max(0.001,min(0.008,rng.lognormvariate(math.log(0.0045),0.40)))
    b=max(0,1-a-cfrac)
    nA,nB,nC=s2_total*a,s2_total*b,s2_total*cfrac
    cash=nA*79+nB*159+nC*349
    mod=day%30; new=[]
    if nA>0: new.append({'g':'S2','type':'small','plan':'A','price':79,'mod':mod,'start':day,'n':nA,'seats':nA})
    if nB>0: new.append({'g':'S2','type':'small','plan':'B','price':159,'mod':mod,'start':day,'n':nB,'seats':nB})
    if nC>0: new.append({'g':'S2','type':'small','plan':'C','price':349,'mod':mod,'start':day,'n':nC,'seats':nC})
    d7_total=max(0,rng.gauss(462*(max(active_d7,1)/24500)**0.32,115))*max(0.55,min(1.20,rng.gauss(1.0+0.05*rec+0.025*scenario,0.11)))
    d7a=max(0.42,min(0.62,rng.gauss(0.50,0.055)))
    d7c=max(0.0,min(0.006,rng.lognormvariate(math.log(0.0015),0.6)))
    d7b=max(0,1-d7a-d7c)
    cash += d7_total*d7a*39 + d7_total*d7b*99 + d7_total*d7c*309
    if d7_total*d7a>0: new.append({'g':'D_S07','type':'small','plan':'A','price':39,'mod':mod,'start':day,'n':d7_total*d7a,'seats':d7_total*d7a})
    if d7_total*d7b>0: new.append({'g':'D_S07','type':'small','plan':'B','price':99,'mod':mod,'start':day,'n':d7_total*d7b,'seats':d7_total*d7b})
    if d7_total*d7c>0: new.append({'g':'D_S07','type':'small','plan':'C','price':309,'mod':mod,'start':day,'n':d7_total*d7c,'seats':d7_total*d7c})
    # Other discovered groups are negligible; most network leads are lost.
    cash += max(0,rng.gauss(800,500))
    leads=(s2_total+d7_total)/0.66 + 500
    return cash,new,leads

def bill_price(g,p,age,stored,day):
    # Current week bridge and likely continuation if first-renewal remains weak.
    if g=='S2':
        if age < 45:
            return {'A':19,'B':129,'C':319}.get(p,stored)
        if age < 75:
            return {'A':79,'B':129,'C':309}.get(p,stored)
        return {'A':79,'B':159,'C':349}.get(p,stored)
    if g=='D_S07':
        if age < 45:
            return {'A':19,'B':59,'C':289}.get(p,stored)
        # after bridge, standing price for legacy/new D_S07
        return {'A':39,'B':99,'C':309}.get(p,stored)
    return stored

def retention(g,p,age,rng,scenario,day):
    rec=qrec(day)
    if g=='S2':
        if age<45:
            # A first-renewal is uncertain despite deep coupon; B observed strong with coupons.
            base={'A':0.54,'B':0.94,'C':0.985}.get(p,0.88)+0.18*rec+0.030*scenario
            sigma={'A':0.16,'B':0.045,'C':0.02}.get(p,0.06)
        elif age<75:
            base={'A':0.84,'B':0.945,'C':0.986}.get(p,0.90)+0.18*rec+0.024*scenario; sigma=0.045
        else:
            base={'A':0.945,'B':0.970,'C':0.992}.get(p,0.95)+0.12*rec+0.016*scenario; sigma=0.026
    elif g=='D_S07':
        if age<45:
            base={'A':0.30,'B':0.52,'C':0.88}.get(p,0.45)+0.14*rec+0.030*scenario; sigma=0.12
        elif age<75:
            base={'A':0.27,'B':0.48,'C':0.88}.get(p,0.50)+0.12*rec+0.028*scenario; sigma=0.10
        else:
            base={'A':0.56,'B':0.74,'C':0.93}.get(p,0.73)+0.10*rec+0.022*scenario; sigma=0.06
    elif g=='E3':
        base=0.975+0.08*rec+0.010*scenario; sigma=0.018
    else:
        base=0.84+0.08*rec+0.025*scenario; sigma=0.05
    return max(0.0,min(0.998,rng.gauss(base,sigma)))

def parse_offer_json(s):
    try:
        data=json.loads(s or '[]')
        if isinstance(data,list):
            return [(o.get('plan'),float(o.get('price_per_seat',o.get('price',0)))) for o in data if isinstance(o,dict)]
        if isinstance(data,dict):
            arr=data.get('offers') or data.get('offerings') or []
            if isinstance(arr,list): return [(o.get('plan'),float(o.get('price_per_seat',o.get('price',0)))) for o in arr if isinstance(o,dict)]
    except Exception: pass
    return []

def ent_events(days,rng,scenario):
    events=[]
    # Enterprise has been near-zero historically; lower prices add upside but keep point conservative.
    mood=max(0.05,min(4.0,rng.lognormvariate(math.log(0.45+0.25*max(scenario,0)),1.05)))
    for p in pipe:
        seats=float(p['seats'] or 0)
        if seats<=0: continue
        g=p['group_id']; age=DAY-int(p['first_day'])
        if g in ('E3','D_E07','D_E08'): mu=0.0048
        elif g in ('E2','D_E02'): mu=0.0038
        else: mu=0.0025
        if age>60: mu*=0.45
        if age>100: mu*=0.25
        pclose=max(0,min(0.16,rng.lognormvariate(math.log(max(mu*mood*(1+0.35*qrec(DAY+min(days,35))),1e-6)),1.0)))
        if rng.random()<pclose:
            if g in ('E1','D_E09'): delay=max(2,int(rng.gauss(10,7)))
            elif g in ('D_E02','E2'): delay=max(4,int(rng.gauss(19,12)))
            else: delay=max(5,int(rng.gauss(27,15)))
            if delay<=days:
                offers=parse_offer_json(p['offer_json'])
                if not offers:
                    offers={'E2':[('A',18),('B',36),('C',95)],'E3':[('A',22),('B',35),('C',95)],'D_E02':[('A',14),('B',30),('C',82)],'D_E07':[('A',20),('B',40),('C',110)],'D_E08':[('A',18),('B',38),('C',100)]}.get(g,[('A',10),('B',24),('C',70)])
                d={k:v for k,v in offers if k and v}
                u=rng.random()
                if g in ('E1','D_E09','D_E02') and 'A' in d and u<0.50: plan='A'
                elif 'B' in d and u<0.88: plan='B'
                elif 'C' in d: plan='C'
                elif 'B' in d: plan='B'
                else: plan='A'
                price=d.get(plan,list(d.values())[0])
                events.append({'day':DAY+delay,'g':g,'type':'large','plan':plan,'price':price,'mod':(DAY+delay)%30,'start':DAY+delay,'n':1,'seats':seats})
    return events

def ent_usage_per_seat_day(g,p):
    if p=='A': return {'E1':18,'E2':60,'E3':45,'D_E02':35,'D_E07':58,'D_E08':40,'D_E09':25}.get(g,40)
    if p=='B': return {'E1':35,'E2':105,'E3':83,'D_E02':70,'D_E07':110,'D_E08':78,'D_E09':45}.get(g,80)
    return {'E1':55,'E2':160,'E3':125,'D_E02':115,'D_E07':170,'D_E08':125,'D_E09':70}.get(g,120)

def compute_cost_per_seat_day(c,day):
    if c['type']=='large': units=ent_usage_per_seat_day(c['g'],c['plan'])
    else: units=usage_per_seat_day.get((c['g'],c['plan']), {'A':175,'B':180,'C':185}.get(c['plan'],180))
    return units*tier_rate(c['plan'],day)

def simulate(days,seed):
    rng=random.Random(seed)
    scenario=max(-1.9,min(1.9,rng.gauss(0,0.70)))
    cash=cash0
    active=[c.copy() for c in active0]
    events=ent_events(days,rng,scenario)
    for day in range(DAY+1,DAY+days+1):
        for e in [x for x in events if x['day']==day]:
            cash += e['price']*e['seats']
            active.append(e.copy())
        active_s2=sum(c['seats'] for c in active if c['g']=='S2')
        active_d7=sum(c['seats'] for c in active if c['g']=='D_S07')
        ncash,new,leads=new_cash_and_cohorts(day,active_s2,active_d7,rng,scenario)
        cash += ncash
        active.extend(new)
        cash -= leadcost_per_day
        newactive=[]
        entseats=sum(c['seats'] for c in active if c['type']=='large')
        # capacity tier7 is not currently enabled; model overload/urgent scale cost if enterprise seats unexpectedly pass 250k.
        extra_cap = 47000 if entseats>250000 else 0
        for c in active:
            cash -= compute_cost_per_seat_day(c,day)*c['seats']
            if day%30 == c['mod'] and day > c['start']:
                age=day-c['start']; ret=retention(c['g'],c['plan'],age,rng,scenario,day)
                kept_n=c['n']*ret; kept_seats=c['seats']*ret
                if kept_n>0:
                    price=bill_price(c['g'],c['plan'],age,c['price'],day)
                    cash += price*kept_seats
                    cc=c.copy(); cc['n']=kept_n; cc['seats']=kept_seats; cc['price']=price
                    newactive.append(cc)
            else:
                newactive.append(c)
        active=newactive
        # Later, ops/dev likely trimmed modestly after support clears; leave most current spend in model.
        fixed=fixed_per_day + extra_cap
        if day-DAY>56:
            s2=sum(c['seats'] for c in active if c['g']=='S2'); d7=sum(c['seats'] for c in active if c['g']=='D_S07'); entseats=sum(c['seats'] for c in active if c['type']=='large')
            ops=5000+190000*(max(s2,1)/151000)**0.50+26000*(max(d7,1)/24500)**0.55+9000
            dev=3000+18000*(max(s2,1)/151000)**0.30+2000*(max(d7,1)/24500)**0.35+7500
            cap=75000 if entseats>250000 or (s2+d7+entseats)>300000 else 28000
            ads=20000
            entops=min(90000,0.10*max(0,entseats-50000))
            fixed=max(285000,min(560000,ops+dev+ads+cap+entops))
        cash -= fixed
    return cash

for days in [7,28,84,182]:
    nseeds=650 if days<=28 else (420 if days<=84 else 260)
    vals=[simulate(days,52000+i) for i in range(nseeds)]
    vals.sort(); mean=statistics.mean(vals); med=statistics.median(vals)
    def pct(p): return vals[max(0,min(len(vals)-1,int(p*len(vals))))]
    print('H',days,'mean',round(mean),'median',round(med),'p2.5',round(pct(.025)),'p10',round(pct(.1)),'p90',round(pct(.9)),'p97.5',round(pct(.975)),'min',round(vals[0]),'max',round(vals[-1]))

